class Solution:
    def arrayChange(self, nums, operations):
        arr = list(nums)
        pos = {v: i for i, v in enumerate(arr)}
        for frm, to in operations:
            i = pos[frm]
            arr[i] = to
            del pos[frm]
            pos[to] = i
        return arr

