var arrayChange = function(nums, operations) {
    const arr = nums.slice();
    const pos = new Map();
    for (let i = 0; i < arr.length; i++) pos.set(arr[i], i);
    for (const [frm, to] of operations) {
        const i = pos.get(frm);
        arr[i] = to;
        pos.delete(frm);
        pos.set(to, i);
    }
    return arr;
};
